// n8n Code node: build Yunwu Gemini generateContent body for 产品营销DNA
// ✅ 数据来源：优先直接从 Webhook 读取业务字段，避免被“下载图片”节点覆盖
// ✅ 有图：优先读取上游“下载图片”的 binary -> inlineData(base64)
// ✅ 无图 / 下载失败：纯文本也能分析（不 throw）

function pickText(v) {
  if (v == null) return '';
  if (typeof v === 'string' || typeof v === 'number' || typeof v === 'boolean') return String(v);

  if (Array.isArray(v)) {
    return v
      .map(x => {
        if (x == null) return '';
        if (typeof x === 'string' || typeof x === 'number' || typeof x === 'boolean') return String(x);
        if (typeof x === 'object') return String(x.text ?? x.value ?? x.name ?? x.url ?? x.link ?? '');
        return '';
      })
      .filter(Boolean)
      .join('\n');
  }

  if (typeof v === 'object') return String(v.text ?? v.value ?? v.name ?? v.url ?? v.link ?? '');
  return String(v);
}

function getField(obj, keyCandidates) {
  for (const k of keyCandidates) {
    if (obj && Object.prototype.hasOwnProperty.call(obj, k)) return pickText(obj[k]);
  }
  return '';
}

function pickBinaryKey(bin) {
  if (!bin || typeof bin !== 'object') return '';
  if (bin.image) return 'image';
  if (bin.data) return 'data';
  const keys = Object.keys(bin);
  return keys.length ? keys[0] : '';
}

async function getBase64FromBinary(itemIndex, binaryKey) {
  const item = $input.all()[itemIndex];
  const bin = item.binary?.[binaryKey];
  if (!bin) return { base64: '', mimeType: '' };

  const mimeType = bin.mimeType || 'image/jpeg';

  if (bin.data && typeof bin.data === 'string' && bin.data.length > 50) {
    return { base64: bin.data, mimeType };
  }

  if (!this?.helpers?.getBinaryDataBuffer) {
    return { base64: '', mimeType };
  }

  const buf = await this.helpers.getBinaryDataBuffer(itemIndex, binaryKey);
  return { base64: buf.toString('base64'), mimeType };
}

const wh = $('Webhook').first().json || {};
const body = (wh.body && typeof wh.body === 'object') ? wh.body : wh;

const productId = getField(body, ['product_id', 'productId', 'id']);
const imageUrl = getField(body, ['image_url', 'imageUrl', 'url']);
const apiKey = getField(body, ['api_key', 'apiKey']);
const workflowId = getField(body, ['workflow_id', 'workflowId']);
const workflowName = getField(body, ['workflow_name', 'workflowName']);

const productName = getField(body, [
  'product_name', 'productName', 'name',
  '产品名称', '产品名', '商品名称', '商品名'
]);

const sellingPts = getField(body, [
  'selling_points', 'sellingPoints',
  '产品卖点（选填）', '核心卖点', '卖点', '产品亮点'
]);

const extraDesc = getField(body, [
  'extra_desc', 'extraDesc', 'description',
  '产品描述', '商品描述', '补充描述', '描述'
]);

const PROMPT_TEXT = `# Role
你是一位资深的**电商选品经理与营销策划专家**。擅长通过一张产品图片，反推其核心卖点、目标人群和视觉特征。

# Task
分析用户上传的产品图片（或描述），输出一份**“产品营销DNA报告”**。这份报告将用于指导后续的视频脚本生成。

# Analysis Logic
1) 视觉外观：颜色、材质、形状、质感（让视频生成AI知道“产品长什么样”）
2) 核心卖点：功能性卖点 + 体验性卖点，并给出可视化证明方式
3) 使用场景与人群：谁在用、在哪用

# Output (STRICT JSON ONLY)
{
  "product_name": "基于图片推断的产品名称",
  "visual_description": "详细视觉描述（给Sora/视频提示词用）",
  "marketing_profile": {
    "target_audience_vibe": "目标用户形象",
    "ideal_environment": "最佳场景",
    "core_selling_points": [
      {
        "type": "Physical",
        "description": "物理特性卖点",
        "visual_proof": "如何用画面证明"
      },
      {
        "type": "Emotional",
        "description": "情感/体验卖点",
        "visual_proof": "如何用画面证明"
      }
    ]
  }
}`;

const userSupplement = [
  `产品名称：${productName || '未提供'}`,
  `产品卖点：${sellingPts || '未提供'}`,
  `产品描述：${extraDesc || '未提供'}`
].join('\n');

const userText = `${PROMPT_TEXT}\n\n${userSupplement}\n\n只输出 JSON，不要 markdown，不要多余文本。`;

const items = $input.all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const bin = item.binary || {};
  const binaryKey = pickBinaryKey(bin);

  let imagePart = null;
  if (binaryKey) {
    try {
      const { base64, mimeType } = await getBase64FromBinary.call(this, i, binaryKey);
      if (base64) {
        imagePart = {
          inlineData: {
            mimeType,
            data: base64
          }
        };
      }
    } catch (e) {
      // 下载失败 / binary 读取失败时，继续纯文本分析
    }
  }

  const parts = [{ text: userText }];
  if (imagePart) parts.push(imagePart);

  const gemini_body = {
    systemInstruction: {
      parts: [{ text: 'Return STRICT JSON only. No markdown. No extra text.' }]
    },
    contents: [
      {
        role: 'user',
        parts
      }
    ],
    generationConfig: {
      responseMimeType: 'application/json',
      temperature: 0.2
    }
  };

  out.push({
    json: {
      ...item.json,
      product_id: productId || null,
      id: productId || null,
      image_url: imageUrl || null,
      api_key: apiKey || null,
      workflow_id: workflowId || null,
      workflow_name: workflowName || null,
      gemini_body,
      _debug_webhook_fields: {
        productId: productId || null,
        imageUrl: imageUrl || null,
        productName: productName || null,
        sellingPts: sellingPts || null,
        extraDesc: extraDesc || null,
        apiKey: apiKey ? '***' : null,
        workflowId: workflowId || null,
        workflowName: workflowName || null
      },
      _debug_image_attached: !!imagePart
    },
    binary: item.binary
  });
}

return out;

// 清洗卖点数据：解析 Gemini 返回 + 补回 Webhook 的 product_id/api_key/workflow_id
// 输出给 Supabase：product_id + selling_points(jsonb) + selling_points_text(string)

const input = $input.first()?.json || {};

let resp = input.body ?? input;

if (typeof resp === 'string') {
  try { resp = JSON.parse(resp); } catch (e) {}
}
if (typeof input.data === 'string') {
  try { resp = JSON.parse(input.data); } catch (e) {}
}

const parts = resp?.candidates?.[0]?.content?.parts;
if (!Array.isArray(parts) || parts.length === 0) {
  throw new Error('Gemini 返回缺少 candidates[0].content.parts');
}

let text = parts.map(p => p?.text || '').join('\n').trim();
if (!text) throw new Error('Gemini parts.text 为空');

text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '');
text = text.replace(/\s*```$/i, '').trim();

let product_dna;
try {
  product_dna = JSON.parse(text);
} catch (e) {
  const head = text.slice(0, 300);
  const tail = text.slice(-300);
  throw new Error(`product_dna JSON.parse 失败：${e.message}\n---HEAD---\n${head}\n---TAIL---\n${tail}`);
}

const wh = $('Webhook').first().json || {};
const whBody = (wh.body && typeof wh.body === 'object') ? wh.body : wh;

const product_id = whBody.product_id ?? null;
const api_key = whBody.api_key ?? null;
const workflow_id = whBody.workflow_id ?? null;

const selling_points = product_dna;

function safe(s) {
  return String(s ?? '').trim();
}

const name = safe(product_dna?.product_name);
const visual = safe(product_dna?.visual_description);

const mp = product_dna?.marketing_profile || {};
const audience = safe(mp?.target_audience_vibe);
const env = safe(mp?.ideal_environment);

const points = Array.isArray(mp?.core_selling_points) ? mp.core_selling_points : [];
const top = points.slice(0, 6).map((p, i) => {
  const type = safe(p?.type) || 'Point';
  const desc = safe(p?.description);
  const proof = safe(p?.visual_proof);
  return `- ${i + 1}.【${type}】${desc}${proof ? `（画面证明：${proof}）` : ''}`;
}).join('\n');

const selling_points_text = [
  `产品名称：${name || '（未识别）'}`,
  audience ? `目标人群：${audience}` : '',
  env ? `核心场景：${env}` : '',
  top ? `核心卖点：\n${top}` : '核心卖点：（无）',
  visual ? `视觉描述：${visual}` : ''
].filter(Boolean).join('\n');

const usage = resp?.usageMetadata ?? resp?.usage ?? {};

return [{
  json: {
    ...input,
    product_id,
    id: product_id,
    api_key,
    workflow_id,
    product_dna,
    usage,
    selling_points,
    selling_points_text
  }
}];

